"use client";

import { useEffect, useState } from "react";
import { api, AuctionSession } from "@/lib/api";

export default function Home() {
  const [upcoming, setUpcoming] = useState<AuctionSession[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api
      .getUpcomingAuctions()
      .then(setUpcoming)
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="text-center py-8">
        <h1 className="text-3xl font-bold text-gray-900">机制币拍讯</h1>
        <p className="mt-2 text-gray-500">
          中国机制币拍卖数据聚合 · 历史成交查询 · 拍卖提醒
        </p>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: "覆盖拍卖行", value: "7家" },
          { label: "拍卖记录", value: "持续更新" },
          { label: "币种收录", value: "200+" },
          { label: "即将拍卖", value: `${upcoming.length}场` },
        ].map((stat) => (
          <div
            key={stat.label}
            className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 text-center"
          >
            <div className="text-2xl font-bold text-primary-700">{stat.value}</div>
            <div className="text-sm text-gray-500 mt-1">{stat.label}</div>
          </div>
        ))}
      </div>

      {/* Upcoming Auctions */}
      <section>
        <h2 className="text-xl font-semibold text-gray-900 mb-4">即将开始的拍卖</h2>
        {loading ? (
          <div className="text-center text-gray-400 py-8">加载中...</div>
        ) : upcoming.length === 0 ? (
          <div className="text-center text-gray-400 py-8 bg-white rounded-lg border">
            暂无即将开始的拍卖
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {upcoming.map((session) => (
              <a
                key={session.id}
                href={`/auctions?id=${session.id}`}
                className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 hover:shadow-md transition-shadow"
              >
                <div className="flex items-start justify-between">
                  <div>
                    <h3 className="font-medium text-gray-900">
                      {session.name_zh || session.name_en}
                    </h3>
                    <p className="text-sm text-gray-500 mt-1">
                      {session.auction_house?.name_zh || ""}
                    </p>
                  </div>
                  <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
                    即将开始
                  </span>
                </div>
                <div className="mt-3 flex items-center text-sm text-gray-500 space-x-4">
                  {session.auction_date && <span>{session.auction_date}</span>}
                  {session.location && <span>{session.location}</span>}
                  {session.total_lots && <span>{session.total_lots}件拍品</span>}
                </div>

